/**
 * Registration Page
 * 
 * Handles new user account creation with form validation. Collects user
 * information including name, email, phone number with country code, password,
 * and country. Includes phone number formatting and password confirmation.
 */

import React, { useState, useEffect, useId, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { authService } from '@/features/auth/services';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { FlagIcon, LoadingSpinner, LanguageSelector, PasswordRequirements } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';
import { createRegisterSchema } from '@/shared/utils/validation/authSchemas.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';
import logger from '@/shared/utils/logger.js';
import '/styles/index.css';
import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';

function Register() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { success, error: showError } = useToast();
  const { effectiveTheme } = useTheme();
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);

  // Generate unique IDs for form inputs for accessibility
  const firstNameId = useId();
  const middleNameId = useId();
  const surnameId = useId();
  const emailId = useId();
  const phoneCountryCodeId = useId();
  const phoneId = useId();
  const countryId = useId();
  const passwordId = useId();
  const confirmPasswordId = useId();

  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;
  const [formData, setFormData] = useState({
    firstName: '',
    middleName: '',
    surname: '',
    email: '',
    phoneCountryCode: '+233',
    phone: '',
    country: '',
    password: '',
    confirmPassword: '',
  });

  const [error, setError] = useState('');
  const [formErrors, setFormErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  const selectedPhoneCountry = countries.find(c => c.dialCode === formData.phoneCountryCode) || countries.find(c => c.code === 'GH');

  /**
   * Translates common API error messages to the current language.
   * Handles registration-specific errors like "email already exists", etc.
   */
  const translateErrorMessage = (errorMessage) => {
    if (!errorMessage) { return ''; }

    const lowerMessage = errorMessage.toLowerCase();

    // Connection refused errors
    if (lowerMessage.includes('econnrefused') || lowerMessage.includes('connection refused')) {
      return t('connectionRefused', { ns: 'auth', defaultValue: 'Unable to connect to our services. Please try again in a few moments.' });
    }

    // Network errors
    if (lowerMessage.includes('network error') || lowerMessage.includes('failed to fetch')) {
      return t('networkError', { ns: 'auth', defaultValue: 'Unable to connect to the server. Please check your internet connection and try again.' });
    }

    if (lowerMessage.includes('timeout') || lowerMessage.includes('timed out')) {
      return t('timeout', { ns: 'auth', defaultValue: 'The request took too long. Please try again.' });
    }

    // Check for account already exists
    if (lowerMessage.includes('already exist') || lowerMessage.includes('already exists') || lowerMessage.includes('409')) {
      return t('accountAlreadyExists', { ns: 'auth' });
    }

    // Check for email already exists
    if (lowerMessage.includes('email') && (lowerMessage.includes('already') || lowerMessage.includes('taken'))) {
      return t('emailAlreadyExists', { ns: 'auth' });
    }

    // Check for phone already exists
    if (lowerMessage.includes('phone') && (lowerMessage.includes('already') || lowerMessage.includes('taken'))) {
      return t('phoneAlreadyExists', { ns: 'auth' });
    }

    // Check for validation errors
    if (lowerMessage.includes('validation') || lowerMessage.includes('invalid')) {
      if (lowerMessage.includes('customermsisdn') || lowerMessage.includes('invalid phone number for')) {
        return t('wrongPhoneNumber', { ns: 'auth', defaultValue: 'Wrong phone number' });
      }
      return errorMessage || t('registrationFailed', { ns: 'auth' });
    }

    // Return original message if no translation pattern found
    return errorMessage;
  };

  const clearFieldError = (name) => {
    if (formErrors[name] || formErrors._form) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[name];
        if (Object.keys(next).length === 1 && next._form) {
          delete next._form;
        }
        return next;
      });
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;

    if (name === 'phone' && value && value.startsWith('0')) {
      const trimmedValue = value.substring(1);
      e.target.value = trimmedValue;
      setFormData((prev) => ({
        ...prev,
        [name]: trimmedValue,
      }));
      clearFieldError(name);
      return;
    }

    // Convert email to lowercase automatically
    const processedValue = name === 'email' ? value.toLowerCase() : value;

    setFormData((prev) => ({
      ...prev,
      [name]: processedValue,
    }));
    clearFieldError(name);
  };



  /**
   * Handles form submission for user registration. Validates password
   * confirmation, formats phone number, and submits registration data
   * to the authentication service.
   */
  const handleSubmit = useCallback(async (e) => {
    e.preventDefault();

    const schema = createRegisterSchema(t);
    const result = schema.safeParse(formData);

    if (!result.success) {
      const errors = mapFieldErrors(result.error);
      setFormErrors(errors);
      const firstError = Object.values(errors)[0];
      const message = firstError || t('pleaseFillAllFields', { ns: 'auth' });
      setError(message);
      showError(message);
      return;
    }

    const validated = result.data;

    setError('');
    setFormErrors({});
    setLoading(true);

    try {
      const cleanedPhone = cleanNumberForBackend(validated.phone);
      const cleanedCountryCode = cleanNumberForBackend(validated.phoneCountryCode || '+233');
      const phone_number = `${cleanedCountryCode}${cleanedPhone}`;

      const userData = {
        first_name: validated.firstName,
        middle_name: validated.middleName,
        last_name: validated.surname,
        email: validated.email,
        phone_number: phone_number,
        country: validated.country,
        password: validated.password,
      };

      await authService.register(userData);

      success(t('accountCreatedSuccessfully', { ns: 'auth' }));
      setTimeout(() => navigate('/login'), 1200);
      setFormData({
        firstName: '',
        middleName: '',
        surname: '',
        email: '',
        phoneCountryCode: '+233',
        phone: '',
        country: '',
        password: '',
        confirmPassword: '',
      });

    } catch (err) {
      logger.error('Signup error', { error: err });
      const rawErrorMessage = err.message || t('registrationFailed', { ns: 'auth' });
      const translatedMessage = translateErrorMessage(rawErrorMessage);
      setError(translatedMessage);
      showError(translatedMessage);
    } finally {
      setLoading(false);
    }
  }, [formData, t, navigate, success, showError]);
  const isMobile = windowWidth <= 480;
  const isTablet = windowWidth <= 768;
  const isSmallMobile = windowWidth <= 360;

  // Responsive positioning for language selector (only for mobile/tablet, desktop handled by CSS)
  const languageSelectorStyle = windowWidth <= 768 ? {
    position: 'absolute',
    top: isSmallMobile ? '6px' : isMobile ? '8px' : isTablet ? '12px' : '20px',
    right: isSmallMobile ? '6px' : isMobile ? '8px' : isTablet ? '12px' : '20px',
    zIndex: 10,
  } : {};

  return (
    <div className="login-container">
      <form className="login-form" onSubmit={handleSubmit} style={{
        paddingTop: isSmallMobile ? '52px' : isMobile ? '56px' : isTablet ? '60px' : '48px'
      }}>
        <div className="language-selector-wrapper" style={windowWidth <= 768 ? languageSelectorStyle : {}}>
          <LanguageSelector />
        </div>
        <img
          src={logoSrc}
          alt="iSmartPay Logo"
          className="login-logo"
          style={{
            transition: 'opacity var(--transition-theme)',
            opacity: 1,
            maxWidth: isSmallMobile ? '100px' : isMobile ? '120px' : isTablet ? '160px' : '180px',
            marginTop: isSmallMobile ? '2px' : isMobile ? '4px' : isTablet ? '8px' : '0',
            marginBottom: isSmallMobile ? '16px' : isMobile ? '20px' : isTablet ? '24px' : '32px'
          }}
        />

        <h2 style={{ marginBottom: '24px' }}>{t('signUpTitle', { ns: 'auth' })}</h2>
        {(error || formErrors._form) && (
          <p className="error" style={{ marginBottom: '16px' }}>
            {formErrors._form ? translateErrorMessage(formErrors._form) : translateErrorMessage(error)}
          </p>
        )}

        <div className="input-wrapper">
          <label htmlFor={firstNameId} className="sr-only">
            {t('firstName', { ns: 'auth' })}
          </label>
          <span className="input-icon"><i className="fa-solid fa-user"></i></span>
          <input
            type="text"
            id={firstNameId}
            name="firstName"
            placeholder={t('firstName', { ns: 'auth' })}
            value={formData.firstName}
            onChange={handleChange}
            required
            aria-describedby={formErrors.firstName ? `${firstNameId}-error` : undefined}
            aria-invalid={!!formErrors.firstName}
          />
        </div>
        {formErrors.firstName && (
          <p
            id={`${firstNameId}-error`}
            role="alert"
            aria-live="polite"
            style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '16px' }}
          >
            {formErrors.firstName}
          </p>
        )}

        <div className="input-wrapper">
          <label htmlFor={middleNameId} className="sr-only">
            {t('middleName', { ns: 'auth' })}
          </label>
          <span className="input-icon"><i className="fa-solid fa-user"></i></span>
          <input
            type="text"
            id={middleNameId}
            name="middleName"
            placeholder={t('middleName', { ns: 'auth' })}
            value={formData.middleName}
            onChange={handleChange}
            aria-describedby={formErrors.middleName ? `${middleNameId}-error` : undefined}
            aria-invalid={!!formErrors.middleName}
          />
        </div>
        {formErrors.middleName && (
          <p
            id={`${middleNameId}-error`}
            role="alert"
            aria-live="polite"
            style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '16px' }}
          >
            {formErrors.middleName}
          </p>
        )}

        <div className="input-wrapper">
          <label htmlFor={surnameId} className="sr-only">
            {t('surname', { ns: 'auth' })}
          </label>
          <span className="input-icon"><i className="fa-solid fa-user"></i></span>
          <input
            type="text"
            id={surnameId}
            name="surname"
            placeholder={t('surname', { ns: 'auth' })}
            value={formData.surname}
            onChange={handleChange}
            required
            aria-describedby={formErrors.surname ? `${surnameId}-error` : undefined}
            aria-invalid={!!formErrors.surname}
          />
        </div>
        {formErrors.surname && (
          <p
            id={`${surnameId}-error`}
            role="alert"
            aria-live="polite"
            style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '16px' }}
          >
            {formErrors.surname}
          </p>
        )}

        <div className="input-wrapper">
          <label htmlFor={emailId} className="sr-only">
            {t('emailAddress', { ns: 'auth' })}
          </label>
          <span className="input-icon"><i className="fa-solid fa-envelope"></i></span>
          <input
            type="email"
            id={emailId}
            name="email"
            placeholder={t('emailAddress', { ns: 'auth' })}
            value={formData.email}
            onChange={handleChange}
            required
            autoComplete="email"
            aria-describedby={formErrors.email ? `${emailId}-error` : undefined}
            aria-invalid={!!formErrors.email}
          />
        </div>
        {formErrors.email && (
          <p
            id={`${emailId}-error`}
            role="alert"
            aria-live="polite"
            style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '16px' }}
          >
            {formErrors.email}
          </p>
        )}

        <div style={{ display: 'flex', gap: '8px', alignItems: 'center', marginBottom: '16px' }}>
          <div style={{ position: 'relative', width: '110px', flexShrink: 0, minWidth: '110px' }}>
            <label htmlFor={phoneCountryCodeId} className="sr-only">
              {t('phoneCountryCode', { ns: 'auth', defaultValue: 'Phone country code' })}
            </label>
            <CustomSelect
              name="phoneCountryCode"
              value={formData.phoneCountryCode}
              onChange={handleChange}
              options={countries.map((country) => ({
                value: country.dialCode,
                label: country.dialCode,
                name: country.name,
                countryCode: country.code,
              }))}
              searchable
              showCheckmark={false}
              style={{ width: '100%' }}
              hasIcon={true}
            />
          </div>
          <div className="input-wrapper" style={{ flex: 1, marginBottom: 0 }}>
            <label htmlFor={phoneId} className="sr-only">
              {t('phoneNumber', { ns: 'auth' })}
            </label>
            <span className="input-icon"><i className="fa-solid fa-phone"></i></span>
            <input
              type="tel"
              id={phoneId}
              name="phone"
              placeholder={t('phoneNumber', { ns: 'auth' })}
              value={formData.phone}
              onChange={handleChange}
              required
              autoComplete="tel"
              aria-describedby={(formErrors.phoneCountryCode || formErrors.phone) ? `${phoneId}-error` : undefined}
              aria-invalid={!!(formErrors.phoneCountryCode || formErrors.phone)}
              style={{ marginBottom: 0 }}
            />
          </div>
        </div>
        {(formErrors.phoneCountryCode || formErrors.phone) && (
          <p
            id={`${phoneId}-error`}
            role="alert"
            aria-live="polite"
            style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '16px' }}
          >
            {formErrors.phone || formErrors.phoneCountryCode}
          </p>
        )}

        <div className="input-wrapper">
          <label htmlFor={countryId} className="sr-only">
            {t('country', { ns: 'auth' })}
          </label>
          <span className="input-icon"><i className="fa-solid fa-earth-africa"></i></span>
          <CustomSelect
            name="country"
            value={formData.country}
            onChange={handleChange}
            options={countries.map(country => ({
              value: country.name,
              label: country.name,
              name: country.name,
              countryCode: country.code,
            }))}
            placeholder={t('country', { ns: 'auth' })}
            required
            searchable
            showCheckmark={false}
            hasIcon={true}
          />
        </div>
        {formErrors.country && (
          <p
            id={`${countryId}-error`}
            role="alert"
            aria-live="polite"
            style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '16px' }}
          >
            {formErrors.country}
          </p>
        )}

        <div className="input-wrapper" style={{ position: 'relative' }}>
          <label htmlFor={passwordId} className="sr-only">
            {t('password', { ns: 'auth' })}
          </label>
          <span className="input-icon"><i className="fa-solid fa-key"></i></span>
          <input
            type={showPassword ? 'text' : 'password'}
            id={passwordId}
            name="password"
            placeholder={t('password', { ns: 'auth' })}
            value={formData.password}
            onChange={handleChange}
            required
            autoComplete="new-password"
            aria-describedby={formErrors.password ? `${passwordId}-error` : undefined}
            aria-invalid={!!formErrors.password}
            style={{ paddingRight: '45px' }}
          />
          <button
            type="button"
            onClick={() => setShowPassword(!showPassword)}
            style={{
              position: 'absolute',
              right: '16px',
              top: '50%',
              transform: 'translateY(-50%)',
              background: 'none',
              border: 'none',
              color: '#6b7280',
              cursor: 'pointer',
              padding: '0',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              width: '20px',
              height: '20px'
            }}
            aria-label={showPassword ? t('hidePassword', { ns: 'auth' }) : t('showPassword', { ns: 'auth' })}
          >
            <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
          </button>
        </div>
        <PasswordRequirements password={formData.password} />
        {formErrors.password && (
          <p
            id={`${passwordId}-error`}
            role="alert"
            aria-live="polite"
            style={{ color: 'var(--error)', fontSize: '12px', marginTop: '8px', marginBottom: '16px' }}
          >
            {formErrors.password}
          </p>
        )}

        <div className="input-wrapper" style={{ position: 'relative' }}>
          <label htmlFor={confirmPasswordId} className="sr-only">
            {t('confirmPassword', { ns: 'auth' })}
          </label>
          <span className="input-icon"><i className="fa-solid fa-key"></i></span>
          <input
            type={showConfirmPassword ? 'text' : 'password'}
            id={confirmPasswordId}
            name="confirmPassword"
            placeholder={t('confirmPassword', { ns: 'auth' })}
            value={formData.confirmPassword}
            onChange={handleChange}
            required
            autoComplete="new-password"
            aria-describedby={formErrors.confirmPassword ? `${confirmPasswordId}-error` : undefined}
            aria-invalid={!!formErrors.confirmPassword}
            style={{ paddingRight: '45px' }}
          />
          <button
            type="button"
            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
            style={{
              position: 'absolute',
              right: '16px',
              top: '50%',
              transform: 'translateY(-50%)',
              background: 'none',
              border: 'none',
              color: '#6b7280',
              cursor: 'pointer',
              padding: '0',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              width: '20px',
              height: '20px'
            }}
            aria-label={showConfirmPassword ? t('hidePassword', { ns: 'auth' }) : t('showPassword', { ns: 'auth' })}
          >
            <i className={`fa-solid ${showConfirmPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
          </button>
        </div>
        {formErrors.confirmPassword && (
          <p
            id={`${confirmPasswordId}-error`}
            role="alert"
            aria-live="polite"
            style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '16px' }}
          >
            {formErrors.confirmPassword}
          </p>
        )}

        <button type="submit" disabled={loading} style={{ width: '100%', marginBottom: '10px', opacity: loading ? 0.7 : 1, cursor: loading ? 'not-allowed' : 'pointer', backgroundColor: '#004895' }}>
          {t('createAccount', { ns: 'auth' })}
        </button>

        {loading && createPortal(
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            width: '100vw',
            height: '100vh',
            backgroundColor: effectiveTheme === 'dark'
              ? 'rgba(0, 0, 0, 0.85)'
              : 'rgba(0, 0, 0, 0.5)',
            backdropFilter: 'blur(4px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 99999,
            margin: 0,
            padding: 0
          }}>
            <div style={{
              backgroundColor: effectiveTheme === 'dark'
                ? '#141414'
                : 'white',
              borderRadius: '16px',
              padding: '48px',
              boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              minWidth: '120px',
              minHeight: '120px'
            }}>
              <LoadingSpinner size="large" />
            </div>
          </div>,
          document.body
        )}

        <hr />
        <p style={{ textAlign: 'center' }}>{t('alreadyHaveAccount', { ns: 'auth' })}</p>

        <button
          type="button"
          onClick={() => navigate('/login')}
          style={{ width: '100%', backgroundColor: '#23bd00' }}
        >
          {t('signInButton', { ns: 'auth' })}
        </button>
      </form>
    </div>
  );
}

export default Register;